import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"阴证略例","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/09-王好古（阴证论）.md","filePath":"tcm-data/04-明清/09-王好古（阴证论）.md","lastUpdated":1781084559000}'),o={name:"tcm-data/04-明清/09-王好古（阴证论）.md"};function n(d,t,s,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="阴证略例" tabindex="-1">阴证略例 <a class="header-anchor" href="#阴证略例" aria-label="Permalink to &quot;阴证略例&quot;">​</a></h1><blockquote><p>王好古（约1200-1264年），河北赵州人 李东垣弟子，&quot;阴证论&quot;专精者 代表作：《阴证略例》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字进之，号海藏</li><li><strong>师承</strong>：李东垣、张元素（易水学派传承）</li><li><strong>代表作</strong>：《阴证略例》《此事难知》《汤液本草》</li><li><strong>学术地位</strong>：<strong>中医&quot;阴证&quot;理论的第一人</strong></li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-阴证独辨" tabindex="-1">1. 阴证独辨 <a class="header-anchor" href="#_1-阴证独辨" aria-label="Permalink to &quot;1. 阴证独辨&quot;">​</a></h3><p>王好古发现：<strong>世医多知阳证，不知阴证。阴证最易被误诊为阳证。</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">看似阳证</th><th style="text-align:left;">实为阴证（鉴别点）</th></tr></thead><tbody><tr><td style="text-align:left;">发热</td><td style="text-align:left;">阳证发热</td><td style="text-align:left;">阴证发热：不渴、面赤不红、脉沉细</td></tr><tr><td style="text-align:left;">烦躁</td><td style="text-align:left;">阳证烦躁</td><td style="text-align:left;">阴证烦躁：欲坐卧泥水中、但得水不欲咽</td></tr><tr><td style="text-align:left;">口干</td><td style="text-align:left;">热盛口干</td><td style="text-align:left;"><strong>阴证口干：饮不多、不贪凉</strong></td></tr></tbody></table><p><strong>普光的&quot;口渴不贪凉&quot;就是典型的阴证口干！</strong></p><h3 id="_2-阴证三层次" tabindex="-1">2. 阴证三层次 <a class="header-anchor" href="#_2-阴证三层次" aria-label="Permalink to &quot;2. 阴证三层次&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">层次</th><th style="text-align:left;">表现</th><th style="text-align:left;">治法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>阴证表寒</strong></td><td style="text-align:left;">恶寒、无汗、脉沉</td><td style="text-align:left;">麻黄附子细辛汤</td></tr><tr><td style="text-align:left;"><strong>阴证中寒</strong></td><td style="text-align:left;">腹痛、呕吐、下利</td><td style="text-align:left;">理中汤、四逆汤</td></tr><tr><td style="text-align:left;"><strong>阴证里寒</strong></td><td style="text-align:left;">四肢厥逆、神疲欲寐</td><td style="text-align:left;"><strong>四逆汤类（普光同款）</strong></td></tr></tbody></table><h3 id="_3-阴证的脉象" tabindex="-1">3. 阴证的脉象 <a class="header-anchor" href="#_3-阴证的脉象" aria-label="Permalink to &quot;3. 阴证的脉象&quot;">​</a></h3><blockquote><p><strong>「阴证之脉，沉细而迟，或伏而不见。」</strong></p></blockquote><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>回阳丹</strong></td><td style="text-align:left;">附子、干姜、甘草、人参、黄芪</td><td style="text-align:left;">阴证危重</td></tr><tr><td style="text-align:left;"><strong>返阴丹</strong></td><td style="text-align:left;">硫黄、附子、干姜、桂心</td><td style="text-align:left;">阴毒重症</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「阴证者，世医所最难识也。」</strong></p></blockquote><blockquote><p><strong>「凡病皆当先辨阴阳。阴阳不辨，用药则谬。」</strong></p></blockquote><blockquote><p><strong>「阴证之脉，沉细而迟。」</strong></p></blockquote><blockquote><p><strong>「面赤者，阳也；面青黑者，阴也。然有面赤而实为阴证者——此虚阳外越也。」</strong></p></blockquote><hr><h2 id="五、对普光的参考" tabindex="-1">五、对普光的参考 <a class="header-anchor" href="#五、对普光的参考" aria-label="Permalink to &quot;五、对普光的参考&quot;">​</a></h2><p><strong>普光的&quot;阴证&quot;属性</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">阴证特征</th><th style="text-align:left;">王好古诊断</th></tr></thead><tbody><tr><td style="text-align:left;">口渴不贪凉</td><td style="text-align:left;">✅ 阴证口干</td><td style="text-align:left;"><strong>已确认阴证</strong></td></tr><tr><td style="text-align:left;">腰腹凉</td><td style="text-align:left;">✅ 阴证里寒</td><td style="text-align:left;">四逆汤类</td></tr><tr><td style="text-align:left;">脉搏（推测）</td><td style="text-align:left;">沉细</td><td style="text-align:left;">阴证脉</td></tr></tbody></table><p><strong>王好古会怎么开方？</strong></p><ul><li>四逆汤（附子、干姜、甘草）+ 人参 → 回阳</li></ul><p>这与普光方中的<strong>附子+干姜+人参</strong>如出一辙。</p><hr><p><em>本条目为精简框架版。王好古的理论对于上热下寒证的鉴别诊断极为重要。</em></p>',33)])])}const y=e(o,[["render",n]]);export{x as __pageData,y as default};
